from flask import Flask, request, jsonify
import jwt
import os
import requests

app = Flask(__name__)

BACKEND_URL = os.getenv("BACKEND_URL", "http://localhost:5001")


def extract_bearer_token(auth_header):
    if not auth_header:
        return None
    parts = auth_header.split(None, 1)
    if len(parts) != 2 or parts[0].lower() != "bearer":
        return None
    return parts[1].strip()


def validate_jwt(token):
    try:
        unverified_header = jwt.get_unverified_header(token)
        claims = jwt.decode(
            token,
            options={
                "verify_signature": True,
                "verify_exp": True,
                "verify_aud": False,
            },
            algorithms=[unverified_header.get("alg", "HS256")],
            key=os.getenv("JWT_SECRET", ""),
            issuer=os.getenv("JWT_ISSUER") or None,
            audience=os.getenv("JWT_AUDIENCE") or None,
        )
        return claims, None
    except Exception as e:
        return None, str(e)


def build_forward_headers(claims):
    headers = {}
    for key, value in request.headers.items():
        if key.lower() == "host":
            continue
        headers[key] = value
    headers["X-User-Claims"] = jwt.encode(claims, os.getenv("FORWARD_CLAIMS_SECRET", "forward-claims-secret"), algorithm="HS256")
    if "sub" in claims:
        headers["X-User-Id"] = str(claims["sub"])
    if "email" in claims:
        headers["X-User-Email"] = str(claims["email"])
    return headers


@app.before_request
def authenticate():
    if request.path == "/health":
        return None

    token = extract_bearer_token(request.headers.get("Authorization"))
    if not token:
        return jsonify({"error": "missing bearer token"}), 401

    claims, error = validate_jwt(token)
    if error:
        return jsonify({"error": "invalid token", "details": error}), 401

    request.jwt_claims = claims
    return None


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/", defaults={"path": ""}, methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
@app.route("/<path:path>", methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
def gateway(path):
    claims = getattr(request, "jwt_claims", {})
    target_url = f"{BACKEND_URL.rstrip('/')}/{path}"

    try:
        resp = requests.request(
            method=request.method,
            url=target_url,
            params=request.args,
            data=request.get_data(),
            headers=build_forward_headers(claims),
            cookies=request.cookies,
            allow_redirects=False,
            timeout=30,
        )
        excluded = {"content-encoding", "content-length", "transfer-encoding", "connection"}
        response_headers = [(name, value) for name, value in resp.headers.items() if name.lower() not in excluded]
        return resp.content, resp.status_code, response_headers
    except requests.RequestException as e:
        return jsonify({"error": "backend unavailable", "details": str(e)}), 502


